1‚Üíimport React, { useState, useEffect } from 'react';
2‚Üíimport { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
3‚Üíimport Login from './components/Login';
4‚Üíimport Dashboard from './components/Dashboard';
5‚Üíimport AdminPanel from './components/AdminPanel';
6‚Üíimport MasterPanel from './components/MasterPanel';
7‚Üíimport NazoratchiPanel from './components/NazoratchiPanel';
8‚Üíimport UsersPanel from './components/UsersPanel';
9‚Üíimport ReportsPanel from './components/ReportsPanel';
10‚Üíimport MechanicPanel from './components/MechanicPanel';
11‚Üíimport Sidebar from './components/Sidebar';
12‚Üí
13‚Üífunction App() {
14‚Üí  const [user, setUser] = useState(JSON.parse(localStorage.getItem('user')) || null);
15‚Üí  const [activeTab, setActiveTab] = useState('run');
16‚Üí
17‚Üí  const handleLogin = (userData) => {
18‚Üí    localStorage.setItem('user', JSON.stringify(userData));
19‚Üí    setUser(userData);
20‚Üí  };
21‚Üí
22‚Üí  const handleLogout = () => {
23‚Üí    localStorage.removeItem('user');
24‚Üí    localStorage.removeItem('token');
25‚Üí    setUser(null);
26‚Üí    setActiveTab('run');
27‚Üí  };
28‚Üí
29‚Üí  const renderContent = () => {
30‚Üí    switch (activeTab) {
31‚Üí      case 'run':
32‚Üí        return <Dashboard user={user} />;
33‚Üí      case 'report':
34‚Üí        return <ReportsPanel user={user} />;
35‚Üí      case 'mechanic':
36‚Üí        return <MechanicPanel user={user} />;
37‚Üí      case 'admin':
38‚Üí        return <AdminPanel user={user} />;
39‚Üí      case 'master':
40‚Üí        return <MasterPanel user={user} />;
41‚Üí      case 'nazoratchi':
42‚Üí        return <NazoratchiPanel user={user} />;
43‚Üí      case 'users':
44‚Üí        return <UsersPanel user={user} />;
45‚Üí      default:
46‚Üí        return <Dashboard user={user} />;
47‚Üí    }
48‚Üí  };
49‚Üí
50‚Üí  return (
51‚Üí    <Router>
52‚Üí      <Routes>
53‚Üí        <Route path="/login" element={!user ? <Login onLogin={handleLogin} /> : <Navigate to="/" />} />
54‚Üí        <Route path="/*" element={
55‚Üí          user ? (
56‚Üí            <div className="app-container">
57‚Üí              <Sidebar user={user} activeTab={activeTab} onTabChange={setActiveTab} onLogout={handleLogout} />
58‚Üí              <div className="main-content">
59‚Üí                {renderContent()}
60‚Üí              </div>
61‚Üí            </div>
62‚Üí          ) : (
63‚Üí            <Navigate to="/login" />
64‚Üí          )
65‚Üí        } />
66‚Üí      </Routes>
67‚Üí    </Router>
68‚Üí  );
69‚Üí}
70‚Üí
71‚Üíexport default App;
EOF

